// COMPLETE, COMPILABLE C code
#include <stdio.h>
int main() {
    int N;
    scanf("%d", &N);
    for (int i = 0; i < N; i++) {
        int Ai;
        scanf("%d", &Ai);
        int maxZeros = 0;
        int num = Ai;
        while (num % 10 == 0) {
            maxZeros++;
            num /= 10;
        }
        int result = Ai;
        for (int j = 1; j <= 10; j++) {
            int temp = Ai;
            for (int k = 0; k < j; k++) {
                temp *= 4;
            }
            for (int k = 0; k < j; k++) {
                temp *= 7;
            }
            int zeros = 0;
            while (temp % 10 == 0) {
                zeros++;
                temp /= 10;
            }
            if (zeros > maxZeros) {
                maxZeros = zeros;
                result = temp;
            }
        }
        printf("%d\n", result);
    }
    return 0;
}

